import { NextRequest, NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

// GET: دریافت تمام گروهها
export async function GET(request: NextRequest) {
  try {
    const groups = await prisma.pageGroup.findMany({
      include: {
        pages: {
          select: {
            id: true,
            title: true,
            language: true,
            status: true
          }
        }
      },
      orderBy: { name: 'asc' }
    });

    return NextResponse.json({
      success: true,
      data: groups
    });

  } catch (error) {
    console.error('Error fetching page groups:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to fetch page groups' },
      { status: 500 }
    );
  }
}

// POST: ایجاد گروه جدید
export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { name, slug, defaultLanguage = 'en' } = body;

    if (!name || !slug) {
      return NextResponse.json(
        { success: false, error: 'Name and slug are required' },
        { status: 400 }
      );
    }

    // بررسی تکراری نبودن slug
    const existing = await prisma.pageGroup.findUnique({
      where: { slug }
    });

    if (existing) {
      return NextResponse.json(
        { success: false, error: 'Slug already exists' },
        { status: 400 }
      );
    }

    const group = await prisma.pageGroup.create({
      data: {
        name,
        slug,
        defaultLanguage
      }
    });

    return NextResponse.json({
      success: true,
      data: group
    });

  } catch (error) {
    console.error('Error creating page group:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to create page group' },
      { status: 500 }
    );
  }
}

// PUT: بهروزرسانی گروه
export async function PUT(request: NextRequest) {
  try {
    const body = await request.json();
    const { id, name, defaultLanguage } = body;

    if (!id) {
      return NextResponse.json(
        { success: false, error: 'Group ID is required' },
        { status: 400 }
      );
    }

    const group = await prisma.pageGroup.update({
      where: { id },
      data: {
        ...(name && { name }),
        ...(defaultLanguage && { defaultLanguage })
      }
    });

    return NextResponse.json({
      success: true,
      data: group
    });

  } catch (error) {
    console.error('Error updating page group:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to update page group' },
      { status: 500 }
    );
  }
}

// DELETE: حذف گروه
export async function DELETE(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const id = searchParams.get('id');

    if (!id) {
      return NextResponse.json(
        { success: false, error: 'Group ID is required' },
        { status: 400 }
      );
    }

    // بررسی اینکه گروه صفحه نداشته باشد
    const group = await prisma.pageGroup.findUnique({
      where: { id },
      include: { pages: true }
    });

    if (!group) {
      return NextResponse.json(
        { success: false, error: 'Group not found' },
        { status: 404 }
      );
    }

    if (group.pages.length > 0) {
      return NextResponse.json(
        { success: false, error: 'Cannot delete group with pages' },
        { status: 400 }
      );
    }

    await prisma.pageGroup.delete({
      where: { id }
    });

    return NextResponse.json({
      success: true,
      message: 'Group deleted successfully'
    });

  } catch (error) {
    console.error('Error deleting page group:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to delete page group' },
      { status: 500 }
    );
  }
}
